import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import { CssBaseline, Box } from '@mui/material';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import PostureAnalysis from './pages/PostureAnalysis';
import RiskAssessment from './pages/RiskAssessment';
import Rehabilitation from './pages/Rehabilitation';
import Settings from './pages/Settings';

const App = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const theme = createTheme({
    palette: {
      mode: darkMode ? 'dark' : 'light',
      primary: {
        main: '#8B5CF6', // Purple
        light: '#A78BFA',
        dark: '#7C3AED',
        contrastText: '#FFFFFF',
      },
      secondary: {
        main: '#EC4899', // Pink neon
        light: '#F472B6',
        dark: '#DB2777',
        contrastText: '#FFFFFF',
      },
      background: {
        default: darkMode ? '#0A0A0F' : '#F8FAFC',
        paper: darkMode ? '#1A1A2E' : '#FFFFFF',
      },
      text: {
        primary: darkMode ? '#E2E8F0' : '#1E293B',
        secondary: darkMode ? '#94A3B8' : '#64748B',
      },
      neon: {
        purple: '#8B5CF6',
        pink: '#EC4899',
        cyan: '#06B6D4',
        green: '#10B981',
      },
    },
    typography: {
      fontFamily: '"Inter", "Roboto", "Helvetica", "Arial", sans-serif',
      h1: {
        fontWeight: 800,
        fontSize: '3rem',
        background: darkMode 
          ? 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)'
          : 'linear-gradient(135deg, #7C3AED 0%, #DB2777 100%)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
      },
      h4: {
        fontWeight: 700,
        fontSize: '2rem',
        background: darkMode 
          ? 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)'
          : 'linear-gradient(135deg, #7C3AED 0%, #DB2777 100%)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
      },
      h6: {
        fontWeight: 600,
        fontSize: '1.25rem',
      },
      body1: {
        fontSize: '1rem',
        lineHeight: 1.6,
      },
    },
    components: {
      MuiCard: {
        styleOverrides: {
          root: {
            borderRadius: 20,
            background: darkMode 
              ? 'linear-gradient(145deg, #1A1A2E 0%, #16213E 100%)'
              : 'linear-gradient(145deg, #FFFFFF 0%, #F8FAFC 100%)',
            border: darkMode 
              ? '1px solid rgba(139, 92, 246, 0.2)'
              : '1px solid rgba(124, 58, 237, 0.1)',
            boxShadow: darkMode
              ? '0 20px 40px rgba(139, 92, 246, 0.1), 0 0 0 1px rgba(139, 92, 246, 0.05), inset 0 1px 0 rgba(255, 255, 255, 0.05)'
              : '0 20px 40px rgba(124, 58, 237, 0.08), 0 0 0 1px rgba(124, 58, 237, 0.05)',
            backdropFilter: 'blur(20px)',
            transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
            '&:hover': {
              transform: 'translateY(-4px)',
              boxShadow: darkMode
                ? '0 32px 64px rgba(139, 92, 246, 0.15), 0 0 0 1px rgba(139, 92, 246, 0.1), inset 0 1px 0 rgba(255, 255, 255, 0.1)'
                : '0 32px 64px rgba(124, 58, 237, 0.12), 0 0 0 1px rgba(124, 58, 237, 0.1)',
            },
          },
        },
      },
      MuiButton: {
        styleOverrides: {
          root: {
            borderRadius: 12,
            textTransform: 'none',
            fontWeight: 600,
            fontSize: '0.95rem',
            padding: '12px 24px',
            transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
            position: 'relative',
            overflow: 'hidden',
            '&::before': {
              content: '""',
              position: 'absolute',
              top: 0,
              left: '-100%',
              width: '100%',
              height: '100%',
              background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent)',
              transition: 'left 0.5s',
            },
            '&:hover::before': {
              left: '100%',
            },
          },
          contained: {
            background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
            boxShadow: '0 8px 32px rgba(139, 92, 246, 0.3)',
            '&:hover': {
              background: 'linear-gradient(135deg, #7C3AED 0%, #DB2777 100%)',
              boxShadow: '0 12px 40px rgba(139, 92, 246, 0.4)',
              transform: 'translateY(-2px)',
            },
          },
          outlined: {
            border: '2px solid',
            borderImage: 'linear-gradient(135deg, #8B5CF6, #EC4899) 1',
            color: darkMode ? '#8B5CF6' : '#7C3AED',
            '&:hover': {
              background: 'rgba(139, 92, 246, 0.1)',
              borderImage: 'linear-gradient(135deg, #7C3AED, #DB2777) 1',
            },
          },
        },
      },
      MuiAppBar: {
        styleOverrides: {
          root: {
            background: darkMode
              ? 'linear-gradient(135deg, #0A0A0F 0%, #1A1A2E 100%)'
              : 'linear-gradient(135deg, #FFFFFF 0%, #F8FAFC 100%)',
            backdropFilter: 'blur(20px)',
            borderBottom: darkMode
              ? '1px solid rgba(139, 92, 246, 0.2)'
              : '1px solid rgba(124, 58, 237, 0.1)',
            boxShadow: darkMode
              ? '0 8px 32px rgba(139, 92, 246, 0.1)'
              : '0 8px 32px rgba(124, 58, 237, 0.08)',
          },
        },
      },
      MuiDrawer: {
        styleOverrides: {
          paper: {
            background: darkMode
              ? 'linear-gradient(180deg, #0A0A0F 0%, #1A1A2E 100%)'
              : 'linear-gradient(180deg, #FFFFFF 0%, #F8FAFC 100%)',
            borderRight: darkMode
              ? '1px solid rgba(139, 92, 246, 0.2)'
              : '1px solid rgba(124, 58, 237, 0.1)',
            backdropFilter: 'blur(20px)',
          },
        },
      },
      MuiLinearProgress: {
        styleOverrides: {
          root: {
            height: 8,
            borderRadius: 4,
            background: darkMode ? 'rgba(139, 92, 246, 0.1)' : 'rgba(124, 58, 237, 0.1)',
          },
          bar: {
            borderRadius: 4,
            background: 'linear-gradient(90deg, #8B5CF6 0%, #EC4899 100%)',
            boxShadow: '0 0 20px rgba(139, 92, 246, 0.5)',
          },
        },
      },
      MuiChip: {
        styleOverrides: {
          root: {
            borderRadius: 8,
            fontWeight: 600,
            backdropFilter: 'blur(10px)',
          },
          colorSuccess: {
            background: 'linear-gradient(135deg, #10B981 0%, #059669 100%)',
            color: '#FFFFFF',
            boxShadow: '0 4px 20px rgba(16, 185, 129, 0.3)',
          },
          colorWarning: {
            background: 'linear-gradient(135deg, #F59E0B 0%, #D97706 100%)',
            color: '#FFFFFF',
            boxShadow: '0 4px 20px rgba(245, 158, 11, 0.3)',
          },
          colorError: {
            background: 'linear-gradient(135deg, #EF4444 0%, #DC2626 100%)',
            color: '#FFFFFF',
            boxShadow: '0 4px 20px rgba(239, 68, 68, 0.3)',
          },
        },
      },
    },
  });

  const toggleDarkMode = () => {
    setDarkMode(!darkMode);
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <Router>
        <Box sx={{ display: 'flex' }}>
          <Navbar 
            darkMode={darkMode} 
            toggleDarkMode={toggleDarkMode}
            toggleSidebar={toggleSidebar}
          />
          <Sidebar open={sidebarOpen} />
          <Box
            component="main"
            sx={{
              flexGrow: 1,
              p: 4,
              mt: 10,
              ml: sidebarOpen ? '280px' : '0px',
              transition: 'margin-left 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
              background: (theme) => 
                theme.palette.mode === 'dark'
                  ? 'radial-gradient(ellipse at top, rgba(139, 92, 246, 0.05) 0%, transparent 50%), linear-gradient(180deg, #0A0A0F 0%, #1A1A2E 100%)'
                  : 'radial-gradient(ellipse at top, rgba(124, 58, 237, 0.03) 0%, transparent 50%), linear-gradient(180deg, #F8FAFC 0%, #FFFFFF 100%)',
              minHeight: '100vh',
              position: 'relative',
              '&::before': {
                content: '""',
                position: 'fixed',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                background: theme.palette.mode === 'dark'
                  ? 'radial-gradient(circle at 20% 80%, rgba(139, 92, 246, 0.1) 0%, transparent 50%), radial-gradient(circle at 80% 20%, rgba(236, 72, 153, 0.1) 0%, transparent 50%)'
                  : 'radial-gradient(circle at 20% 80%, rgba(124, 58, 237, 0.05) 0%, transparent 50%), radial-gradient(circle at 80% 20%, rgba(219, 39, 119, 0.05) 0%, transparent 50%)',
                pointerEvents: 'none',
                zIndex: -1,
              },
            }}
          >
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/analysis" element={<PostureAnalysis />} />
              <Route path="/risk" element={<RiskAssessment />} />
              <Route path="/rehabilitation" element={<Rehabilitation />} />
              <Route path="/settings" element={<Settings />} />
            </Routes>
          </Box>
        </Box>
      </Router>
    </ThemeProvider>
  );
};

export default App;
